class UserIdValidator @Inject constructor(
    private val firebaseAuth: FirebaseAuth
) {

    fun validateCurrentUser(): LiftrixResult<UserId> {
        val firebaseUser = firebaseAuth.currentUser
            ?: return LiftrixResult.Error(LiftrixError.UserNotAuthenticated())

        return LiftrixResult.Success(UserId(firebaseUser.uid))
    }

    fun validateUserContext(
        requestedUserId: UserId,
        operation: String
    ): LiftrixResult<Unit> {
        return when (val currentUserResult = validateCurrentUser()) {
            is LiftrixResult.Success -> {
                if (currentUserResult.data == requestedUserId) {
                    LiftrixResult.Success(Unit)
                } else {
                    LiftrixResult.Error(
                        LiftrixError.UnauthorizedAccess(
                            "User ${currentUserResult.data.value} cannot access data for ${requestedUserId.value} in operation: $operation"
                        )
                    )
                }
            }
            is LiftrixResult.Error -> currentUserResult
        }
    }
}

@Composable
fun EditSessionScreen(
    sessionId: WorkoutSessionId,
    viewModel: EditSessionViewModel = hiltViewModel(),
    onNavigateBack: () -> Unit
) {
    val uiState by viewModel.uiState.collectAsStateWithLifecycle()

    LaunchedEffect(sessionId) {
        viewModel.loadSession(sessionId)
    }

    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(LiftrixSpacing.screenPadding)
    ) {
        // Header with clear editing indicator
        Row(
            modifier = Modifier.fillMaxWidth(),
            verticalAlignment = Alignment.CenterVertically
        ) {
            LiftrixIcon(
                icon = LiftrixIcons.Edit,
                contentDescription = "Editing historical session",
                tint = LiftrixColors.CoralAccent
            )
            Spacer(modifier = Modifier.width(8.dp))
            Text(
                text = "Editing historical workout session",
                style = MaterialTheme.typography.headlineSmall,
                color = MaterialTheme.colorScheme.onSurface
            )
        }

        when (uiState) {
            is EditSessionUiState.Loading -> {
                WorkoutCardSkeleton()
            }
            is EditSessionUiState.Success -> {
                EditSessionContent(
                    session = uiState.session,
                    onExerciseUpdate = viewModel::updateExercise,
                    onSetUpdate = viewModel::updateSet,
                    onSaveChanges = viewModel::saveChanges,
                    hasChanges = uiState.hasChanges
                )
            }
            is EditSessionUiState.Error -> {
                LiftrixErrorState(
                    error = uiState.error,
                    onRetry = { viewModel.loadSession(sessionId) },
                    onDismiss = onNavigateBack
                )
            }
        }
    }
}

