class PerformanceValidator @Inject constructor(
    private val choreographer: Choreographer,
    private val analyticsService: AnalyticsService
) {

    private val frameMetrics = mutableListOf<Long>()
    private var monitoringSession: String? = null

    fun startFrameMonitoring(sessionId: String) {
        monitoringSession = sessionId
        frameMetrics.clear()

        choreographer.postFrameCallback(frameCallback)
    }

    fun stopFrameMonitoring(): PerformanceReport {
        choreographer.removeFrameCallback(frameCallback)

        val report = generatePerformanceReport()

        analyticsService.logEvent("performance_validation") {
            param("session_id", monitoringSession ?: "unknown")
            param("average_fps", report.averageFps)
            param("frame_drops", report.frameDropCount)
            param("meets_60fps_target", report.meets60FpsTarget)
        }

        return report
    }

    private val frameCallback = object : Choreographer.FrameCallback {
        private var lastFrameTime = 0L

        override fun doFrame(frameTimeNanos: Long) {
            if (lastFrameTime != 0L) {
                val frameDuration = frameTimeNanos - lastFrameTime
                frameMetrics.add(frameDuration)
            }

            lastFrameTime = frameTimeNanos

            if (monitoringSession != null) {
                choreographer.postFrameCallback(this)
            }
        }
    }

    private fun generatePerformanceReport(): PerformanceReport {
        val frameTimesMs = frameMetrics.map { it / 1_000_000.0 }
        val averageFrameTime = frameTimesMs.average()
        val averageFps = 1000.0 / averageFrameTime

        val frameDrops = frameTimesMs.count { it > 16.67 } // 60fps = 16.67ms per frame
        val frameDropPercentage = (frameDrops.toDouble() / frameTimesMs.size) * 100

        return PerformanceReport(
            averageFps = averageFps,
            frameDropCount = frameDrops,
            frameDropPercentage = frameDropPercentage,
            meets60FpsTarget = frameDropPercentage < 5.0 // Allow 5% frame drops
        )
    }
}

data class PerformanceReport(
    val averageFps: Double,
    val frameDropCount: Int,
    val frameDropPercentage: Double,
    val meets60FpsTarget: Boolean
)

class GreyUsageAnalyzer {

    fun analyzeComponentGreyUsage(componentColors: List<Color>): GreyUsageReport {
        val totalColors = componentColors.size
        val greyColors = componentColors.filter { isGreyColor(it) }
        val greyPercentage = (greyColors.size.toDouble() / totalColors) * 100.0

        return GreyUsageReport(
            totalColors = totalColors,
            greyColors = greyColors.size,
            greyPercentage = greyPercentage,
            meetsTarget = greyPercentage < 20.0,
            violatingColors = greyColors,
            recommendations = generateRecommendations(greyColors)
        )
    }

    private fun isGreyColor(color: Color): Boolean {
        val tolerance = 0.05f
        val r = color.red
        val g = color.green  
        val b = color.blue

        // Check if RGB values are approximately equal (grey characteristic)
        val avgValue = (r + g + b) / 3f
        return abs(r - avgValue) < tolerance &&
               abs(g - avgValue) < tolerance &&
               abs(b - avgValue) < tolerance
    }

    private fun generateRecommendations(greyColors: List<Color>): List<ColorRecommendation> {
        return greyColors.map { greyColor ->
            when {
                greyColor.luminance() > 0.8f -> ColorRecommendation(
                    original = greyColor,
                    replacement = LiftrixColors.Surface,
                    reason = "Use semantic surface color instead of light grey"
                )
                greyColor.luminance() > 0.5f -> ColorRecommendation(
                    original = greyColor,
                    replacement = LiftrixColors.SurfaceVariant,
                    reason = "Use surface variant instead of medium grey"
                )
                else -> ColorRecommendation(
                    original = greyColor,
                    replacement = LiftrixColors.Primary.copy(alpha = 0.1f),
                    reason = "Use teal tint instead of dark grey"
                )
            }
        }
    }
}

data class GreyUsageReport(
    val totalColors: Int,
    val greyColors: Int,
    val greyPercentage: Double,
    val meetsTarget: Boolean,
    val violatingColors: List<Color>,
    val recommendations: List<ColorRecommendation>
)

data class ColorRecommendation(
    val original: Color,
    val replacement: Color,
    val reason: String
)

