class FeatureFlagManager @Inject constructor(
    private val userPreferences: UserPreferences,
    private val analyticsService: AnalyticsService
) {

    suspend fun isUiRedesignEnabled(userId: String): Boolean {
        // Check user-specific override first
        val userOverride = userPreferences.getUiRedesignOverride()
        if (userOverride != null) {
            return userOverride
        }

        // Get current rollout percentage from remote config
        val rolloutPercentage = getRemoteRolloutPercentage()

        // Determine if user is in rollout group based on stable hash
        val userHash = userId.hashCode().absoluteValue % 100
        val isInRollout = userHash < rolloutPercentage

        // Track rollout assignment for analytics
        analyticsService.logEvent("ui_redesign_rollout_assignment") {
            param("user_id", userId)
            param("rollout_percentage", rolloutPercentage)
            param("is_in_rollout", isInRollout)
        }

        return isInRollout
    }

    suspend fun enableUiRedesignForUser(userId: String, enabled: Boolean) {
        userPreferences.setUiRedesignOverride(enabled)

        analyticsService.logEvent("ui_redesign_manual_override") {
            param("user_id", userId)
            param("enabled", enabled)
            param("timestamp", System.currentTimeMillis())
        }
    }

    private suspend fun getRemoteRolloutPercentage(): Int {
        // Implementation would fetch from Firebase Remote Config
        return 10 // Start with 10% rollout
    }
}

class UiRedesignMonitor @Inject constructor(
    private val analyticsService: AnalyticsService,
    private val rollbackStrategy: RollbackStrategy
) {

    fun trackUiInteraction(
        interactionType: String,
        responseTime: Long,
        successful: Boolean
    ) {
        analyticsService.logEvent("ui_redesign_interaction") {
            param("interaction_type", interactionType)
            param("response_time_ms", responseTime)
            param("successful", successful)
        }

        // Check for critical performance degradation
        if (responseTime > 1000) { // 1 second threshold
            rollbackStrategy.evaluateRollbackNeed(
                reason = "Performance degradation detected",
                severity = if (responseTime > 5000) "critical" else "warning"
            )
        }
    }
}

